form:Form.form:Scripts:
		function btnSave_onValidate()
{
 //Validar MAIL
  var mail = Ctrl('d_email').GetXValue();
  var patron = /^[A-Za-z][A-Za-z0-9_]*@[A-Za-z0-9_]+\.[A-Za-z0-9_.]+[A-za-z]$/;

	if(mail!='')
		{   

			  if(!(patron.test(mail)))
			  	{      

			  		Ctrl('SAVE').SetError('Mail Inválido');  		
			  		return false;   	
			  	} 
		}

 return true;
}
